const AIService={async getGeminiConfig(){return{...SettingsService.defaults.gemini,...(await SettingsService.loadSettingRow(SettingsService.rows.geminiReports)||{})};}, async getDeepSeekConfig(){return{...SettingsService.defaults.deepseek,...(await SettingsService.loadSettingRow(SettingsService.rows.legacyDeepseek)||{}),...(await SettingsService.loadSettingRow(SettingsService.rows.deepseekAnswers)||{})};}, collectInstructionContext(){const text=[...$$('.guide-block')].map(b=>b.innerText||b.textContent||'').join('\n\n').replace(/\s+/g,' ').trim(); return text||'Проверяй контекст, доказательства и соразмерность наказания.';}, async askInstruction(question){const cfg=await this.getDeepSeekConfig(); if(!cfg.apiKey)throw new Error('DeepSeek API key не настроен.'); return this.callChatCompletion({apiKey:cfg.apiKey,endpoint:cfg.endpoint,model:cfg.model,messages:[{role:'system',content:'Ты помощник панели модерации. Отвечай кратко по правилам. Контекст: '+this.collectInstructionContext().slice(0,9000)},{role:'user',content:question}],temperature:.25,thinking:cfg.thinking!==false});}, async analyzeReport(row){const cfg=await this.getGeminiConfig(); if(!cfg.apiKey)throw new Error('Gemini API key не настроен.'); const prompt=['Проанализируй отчёт модератора. Верни строго JSON без markdown: {"status":"...","xp":0,"reason":"...","risks":[],"questions":[]}.','Статусы: Натяг 7, Норма 15, Перенорма 25, Герой дня 40, Не засчитано 0.',JSON.stringify({id:row.id,email:row.email,status:row.status,xp:row.xp,parsed:ReportModule.parseReportPayload(row),rawDate:row.date},null,2)].join('\n'); return this.parseAiJson(await this.callGemini({apiKey:cfg.apiKey,endpoint:cfg.endpoint,prompt}));}, async callGemini({apiKey,endpoint,prompt}){const res=await fetch(`${endpoint}?key=${encodeURIComponent(apiKey)}`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({contents:[{role:'user',parts:[{text:prompt}]}],generationConfig:{temperature:.2,maxOutputTokens:1200}})}); const data=await this.safeJson(res); if(!res.ok)throw new Error(this.extractApiError(data,`Gemini error ${res.status}`)); const text=data?.candidates?.[0]?.content?.parts?.map(p=>p.text||'').join('').trim(); if(!text)throw new Error('Gemini вернул пустой ответ.'); return text;}, async callChatCompletion({apiKey,endpoint,model,messages,temperature=.3,thinking=true}){let body={model,messages,temperature,stream:false}; if(thinking)body.reasoning={enabled:true}; let res=await fetch(endpoint,{method:'POST',headers:{'Content-Type':'application/json',Authorization:`Bearer ${apiKey}`},body:JSON.stringify(body)}); if(!res.ok&&thinking)res=await fetch(endpoint,{method:'POST',headers:{'Content-Type':'application/json',Authorization:`Bearer ${apiKey}`},body:JSON.stringify({model,messages,temperature,stream:false})}); const data=await this.safeJson(res); if(!res.ok)throw new Error(this.extractApiError(data,`AI error ${res.status}`)); const answer=data?.choices?.[0]?.message?.content?.trim(); if(!answer)throw new Error('AI вернул пустой ответ.'); return answer;}, parseAiJson(text){const cleaned=String(text||'').replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/```$/i,'').trim(); try{return JSON.parse(cleaned);}catch{const m=cleaned.match(/\{[\s\S]*\}/); if(m)try{return JSON.parse(m[0]);}catch{}} return{status:'Норма',xp:15,reason:cleaned||'Нет JSON.',risks:[],questions:[]};}, async safeJson(res){const t=await res.text(); try{return JSON.parse(t);}catch{return{raw:t};}}, extractApiError(data,fallback){return data?.error?.message||data?.message||data?.raw||fallback;}}
;
const AIModule={async submitChat(form,btn){const input=byId('aiChatInput'),q=normalizeText(input?.value); if(!q)return; this.appendMessage('user','Вы',q); input.value=''; UI.setBusy(btn,true,'Думаю...'); UI.setText('aiChatStatus','AI анализирует...'); try{const a=await AIService.askInstruction(q); this.appendMessage('bot','AI помощник',a); UI.setText('aiChatStatus','Ответ получен.');}catch(e){this.appendMessage('bot error','AI помощник',e.message); UI.setText('aiChatStatus',e.message); UI.toast(e.message,'error');}finally{UI.setBusy(btn,false);}}, appendMessage(type,author,text){const root=byId('aiChatMessages'); if(!root)return; root.insertAdjacentHTML('beforeend',`<div class="ai-message ${type.includes('user')?'user':'bot'} ${type.includes('error')?'error':''}"><strong>${escapeHTML(author)}:</strong><p>${escapeHTML(text).replace(/\n{2,}/g,'</p><p>').replace(/\n/g,'<br>')}</p></div>`); root.scrollTop=root.scrollHeight;}, clearChat(){UI.setHTML('aiChatMessages','<div class="ai-message bot"><strong>AI помощник:</strong><p>Задайте вопрос по правилам модерации.</p></div>');}, useExample(text){const i=byId('aiChatInput'); if(i){i.value=text;i.focus();}}, async analyzeReport(id){if(!AccessService.can('leadership')){UI.toast('Недостаточно прав.','error');return;} const card=document.querySelector(`[data-report-id="${cssEscape(id)}"]`),root=card?.querySelector('[data-ai-report-result]'); if(root)root.innerHTML='<div class="muted">AI анализирует...</div>'; try{const {data,error}=await SupabaseService.client.from(CONFIG.tables.reports).select('*').eq('id',id).maybeSingle(); if(error||!data)throw new Error('Отчёт не найден.'); const result=this.normalizeReportDecision(await AIService.analyzeReport(data)); if(root)root.innerHTML=this.renderReportAnalysis(result,id); UI.toast(`AI рекомендует: ${result.status}`,'success');}catch(e){if(root)root.innerHTML=`<div class="notice notice-danger">${escapeHTML(e.message)}</div>`; UI.toast(e.message,'error');}}, normalizeReportDecision(r){const allowed=new Map([['Натяг',7],['Норма',15],['Перенорма',25],['Герой дня',40],['Не засчитано',0]]); let status=normalizeText(r?.status)||'Норма'; if(!allowed.has(status))status='Норма'; return{status,xp:allowed.get(status),reason:normalizeText(r?.reason)||'AI не указал причину.',risks:Array.isArray(r?.risks)?r.risks:[],questions:Array.isArray(r?.questions)?r.questions:[]};}, renderReportAnalysis(r,id){return `<div class="ai-report-analysis"><div class="ai-report-main"><span>AI рекомендация</span><strong>${escapeHTML(r.status)} · ${escapeHTML(r.xp)} XP</strong></div><p>${escapeHTML(r.reason)}</p><div class="form-actions"><button class="btn btn-primary" type="button" data-action="reports:approve" data-id="${escapeHTML(id)}" data-status="${escapeHTML(r.status)}" data-xp="${escapeHTML(r.xp)}">Применить рекомендацию</button></div></div>`;}, searchInstruction(q){const v=normalizeText(q).toLowerCase(); $$('.guide-block').forEach(b=>{b.hidden=!!v&&!String(b.innerText||b.textContent||'').toLowerCase().includes(v);});}, scrollToBlock(id){byId(id)?.scrollIntoView({behavior:'smooth',block:'start'});}}
;

const TrainerModule={scenarios:[{id:'ad_1',author:'User_4821',text:'Заходите на мой дискорд, ссылка в профиле.',verdict:'ban',explanation:'Реклама стороннего ресурса.',reward:3},{id:'spam_1',author:'xx_nikita_xx',text:'АААААААААААААААААААА',verdict:'warn',explanation:'Флуд / спам.',reward:2},{id:'insult_1',author:'Maksim',text:'Ты вообще тупой? Удали игру.',verdict:'warn',explanation:'Оскорбление участника.',reward:2},{id:'threat_1',author:'Sergey',text:'Я тебя сейчас найду, понял?',verdict:'ban',explanation:'Угроза.',reward:3},{id:'ok_1',author:'Artem',text:'Не согласен с решением, можно пересмотреть жалобу?',verdict:'ok',explanation:'Нарушения нет.',reward:1}],complaintScenarios:[{id:'complaint_1',title:'Жалоба на оскорбление',text:'Есть скрин одного сообщения.',correctAction:'request-context',explanation:'Нужно проверить контекст.'},{id:'complaint_2',title:'Жалоба на рекламу',text:'Прямая ссылка на сторонний сервер.',correctAction:'accept',explanation:'Доказательство читаемое, жалобу можно принять.'},{id:'complaint_3',title:'Жалоба без доказательств',text:'Игрок пишет: поверьте.',correctAction:'reject',explanation:'Без доказательств нельзя засчитать.'}], async init(){this.renderStats(); await this.loadHiddenCheck();}, pickScenario(){return this.scenarios[Math.floor(Math.random()*this.scenarios.length)];}, start(){const s=this.pickScenario(); AppState.trainer.current=s; UI.setText('trainerTitle','Разберите ситуацию'); UI.setText('trainerAuthor',s.author); UI.setText('trainerText',s.text); UI.setMessage('trainerResult','');}, reset(){AppState.trainer={current:null,total:0,correct:0}; UI.setText('trainerTitle','Ожидание задания'); UI.setText('trainerAuthor','Автор скрыт'); UI.setText('trainerText','Нажмите «Начать смену», чтобы получить ситуацию.'); UI.setMessage('trainerResult',''); this.renderStats();}, async verdict(v){const s=AppState.hiddenCheck.current||AppState.trainer.current; if(!s){UI.toast('Сначала начните смену.','warning');return;} const ok=v===s.verdict; AppState.trainer.total++; if(ok){AppState.trainer.correct++; await this.reward(s.reward||1,`Тренажёр: ${s.id}`);} UI.setMessage('trainerResult',ok?`Верно. ${s.explanation}`:`Неверно. Правильно: ${this.verdictLabel(s.verdict)}. ${s.explanation}`,ok?'success':'error'); if(AppState.hiddenCheck.current)await this.finishHiddenCheck(ok,v); this.renderStats(); window.setTimeout(()=>this.start(),700);}, skip(){UI.setMessage('trainerResult','Ситуация пропущена.','warning');this.start();}, verdictLabel(v){return({ok:'Нет нарушения',warn:'Пред / Мут',ban:'Бан / Перма'})[v]||v;}, renderStats(){const t=AppState.trainer.total,c=AppState.trainer.correct; UI.setText('trainerResolved',t); UI.setText('trainerAccuracy',t?`${Math.round(c/t*100)}%`:'0%');}, async reward(amount,reason){const v=parseNumber(amount,0); if(!v)return; await this.incrementModCorrect(v); await AdminLogModule.write({action:'trainer_reward',targetId:AppState.user?.id||'',targetLabel:getUserNickname(AppState.user,AppState.profile),details:{amount:v,reason}}); await XpService.refreshUiBalances();}, async incrementModCorrect(amount){const user=AuthService.requireUser(),p=await UserService.refreshCurrentProfile(); await SupabaseService.client.from(CONFIG.tables.userStats).update({mod_correct:parseNumber(p?.mod_correct,0)+amount,updated_at:nowISO()}).eq('user_id',user.id);}, async loadHiddenCheck(){if(!AppState.user)return; const {data}=await SupabaseService.client.from(CONFIG.tables.reports).select('*').eq('email','HIDDEN_CHECK').eq('link',AppState.user.id).eq('xp',0).order('id',{ascending:false}).limit(1); const row=data?.[0]; if(!row)return; const s={id:row.id,author:'Скрытая проверка',text:row.date,verdict:['ok','warn','ban'].includes(row.status)?row.status:'ok',explanation:'Скрытая проверка от руководства.',reward:5,hiddenRow:row}; AppState.hiddenCheck.current=s;AppState.trainer.current=s; UI.openView('moderation',{silent:true}); UI.setText('trainerTitle','Скрытая проверка');UI.setText('trainerAuthor',s.author);UI.setText('trainerText',s.text);UI.setMessage('trainerResult','Руководство отправило скрытую проверку.','warning');}, async finishHiddenCheck(ok,v){const cur=AppState.hiddenCheck.current; if(!cur?.hiddenRow?.id)return; await SupabaseService.client.from(CONFIG.tables.reports).update({xp:ok?1:-1,status:`${cur.hiddenRow.status}|answer:${v}`}).eq('id',cur.hiddenRow.id); AppState.hiddenCheck.current=null;}}
;
const TimeAttackModule={start(){if(AppState.timeAttack.active)return; AppState.timeAttack={...AppState.timeAttack,active:true,startedAt:performance.now(),total:0,correct:0,current:null}; this.nextQuestion(); this.tick();}, reset(){this.stop(); AppState.timeAttack.total=0;AppState.timeAttack.correct=0;UI.setText('timeAttackTimer','00:00');UI.setHTML('timeAttackArea','');}, stop(){AppState.timeAttack.active=false; if(AppState.timeAttack.rafId)cancelAnimationFrame(AppState.timeAttack.rafId);}, tick(){if(!AppState.timeAttack.active)return; const left=Math.max(0,AppState.timeAttack.durationMs-(performance.now()-AppState.timeAttack.startedAt)); const sec=Math.ceil(left/1000); UI.setText('timeAttackTimer',`${String(Math.floor(sec/60)).padStart(2,'0')}:${String(sec%60).padStart(2,'0')}`); if(left<=0){this.finish();return;} AppState.timeAttack.rafId=requestAnimationFrame(()=>this.tick());}, nextQuestion(){if(!AppState.timeAttack.active)return; const s=TrainerModule.pickScenario(); AppState.timeAttack.current=s; UI.setHTML('timeAttackArea',`<article class="timeattack-card"><p class="message-author">${escapeHTML(s.author)}</p><p class="message-text">${escapeHTML(s.text)}</p><div class="action-grid"><button class="action-btn success" type="button" data-action="timeattack:answer" data-verdict="ok">Нет нарушения</button><button class="action-btn warning" type="button" data-action="timeattack:answer" data-verdict="warn">Пред / Мут</button><button class="action-btn danger" type="button" data-action="timeattack:answer" data-verdict="ban">Бан / Перма</button></div></article>`);}, async answer(v){if(!AppState.timeAttack.active)return; const s=AppState.timeAttack.current; if(!s)return; AppState.timeAttack.total++; if(v===s.verdict)AppState.timeAttack.correct++; this.nextQuestion();}, async finish(){this.stop(); const t=AppState.timeAttack.total,c=AppState.timeAttack.correct,acc=t?Math.round(c/t*100):0,reward=Math.max(0,c*2+(acc>=80?10:0)); if(reward)await TrainerModule.reward(reward,`На время: ${c}/${t}`); UI.setHTML('timeAttackArea',`<article class="timeattack-result"><h3>Результат</h3><p>Верно: <b>${c}</b> из <b>${t}</b></p><p>Точность: <b>${acc}%</b></p><p>Награда: <b>${reward} XP</b></p></article>`);}}
;
const ComplaintsModule={render(){const root=byId('complaintsArea'); if(!root)return; root.innerHTML=TrainerModule.complaintScenarios.map(i=>`<article class="complaint-card" data-complaint-id="${escapeHTML(i.id)}"><h3>${escapeHTML(i.title)}</h3><p>${escapeHTML(i.text)}</p><div class="action-grid"><button class="action-btn success" type="button" data-action="complaints:answer" data-id="${escapeHTML(i.id)}" data-choice="accept">Принять</button><button class="action-btn warning" type="button" data-action="complaints:answer" data-id="${escapeHTML(i.id)}" data-choice="request-context">Запросить контекст</button><button class="action-btn danger" type="button" data-action="complaints:answer" data-id="${escapeHTML(i.id)}" data-choice="reject">Отклонить</button></div><div class="result-box" data-complaint-result></div></article>`).join('');}, async answer(id,choice){const item=TrainerModule.complaintScenarios.find(i=>i.id===id); if(!item)return; const result=document.querySelector(`[data-complaint-id="${cssEscape(id)}"]`)?.querySelector('[data-complaint-result]'); const ok=choice===item.correctAction; if(ok)await TrainerModule.reward(3,`Жалоба: ${id}`); if(result){result.textContent=ok?`Верно. ${item.explanation}`:`Неверно. ${item.explanation}`; result.className=`result-box ${ok?'success':'error'}`;} UI.toast(ok?'Жалоба разобрана верно.':'Ошибка в разборе. ',ok?'success':'warning');}}
;
const QuestsModule={quests:[{id:'quest_5_correct',title:'Точный глаз',description:'Дайте 5 правильных ответов.',reward:15,isDone:()=>AppState.trainer.correct>=5},{id:'quest_10_total',title:'Смена без паники',description:'Разберите 10 ситуаций.',reward:20,isDone:()=>AppState.trainer.total>=10},{id:'quest_timeattack_5',title:'Быстрый разбор',description:'Дайте 5 правильных ответов в режиме на время.',reward:20,isDone:()=>AppState.timeAttack.correct>=5}], render(){const root=byId('questsArea'); if(!root)return; root.innerHTML=this.quests.map(q=>{const done=AppState.quests.completed.has(q.id),ready=q.isDone(); return`<article class="quest-card ${done?'is-completed':''}"><div><h3>${escapeHTML(q.title)}</h3><p>${escapeHTML(q.description)}</p><span>${q.reward} XP</span></div><button class="btn ${ready&&!done?'btn-primary':'btn-secondary'}" type="button" data-action="quests:claim" data-id="${escapeHTML(q.id)}" ${ready&&!done?'':'disabled'}>${done?'Получено':ready?'Забрать':'Не готово'}</button></article>`;}).join('');}, async claim(id){const q=this.quests.find(x=>x.id===id); if(!q||AppState.quests.completed.has(id)||!q.isDone())return; AppState.quests.completed.add(id); await TrainerModule.reward(q.reward,`Квест: ${q.title}`); await this.saveCompletedQuest(id,q); UI.toast(`Квест выполнен: ${q.title}.`,'success'); this.render();}, async saveCompletedQuest(id,q){const user=AuthService.requireUser(); await SupabaseService.client.from(CONFIG.tables.reports).insert([{id:makeId('quest'),email:'QUEST_DONE',link:user.id,date:JSON.stringify({id,title:q.title,reward:q.reward,completedAt:nowISO()}),status:'done',xp:q.reward}]);}, async loadCompleted(){if(!AppState.user)return; const {data}=await SupabaseService.client.from(CONFIG.tables.reports).select('date').eq('email','QUEST_DONE').eq('link',AppState.user.id).limit(1000); AppState.quests.completed=new Set((data||[]).map(r=>{try{return JSON.parse(r.date||'{}').id}catch{return''}}).filter(Boolean));}}
;
const LeaderboardModule={async load(){const root=byId('leaderboardList'); if(!root)return; root.innerHTML='<div class="muted">Загружаю лидерборд...</div>'; try{const {data,error}=await SupabaseService.client.from(CONFIG.tables.userStats).select('user_id,nickname,email,mod_correct,shop_spent,xp').limit(1000); if(error)throw error; const rows=(data||[]).map(r=>({...r,score:parseNumber(r.mod_correct??r.xp,0)-parseNumber(r.shop_spent,0)})).sort((a,b)=>b.score-a.score).slice(0,10); root.innerHTML=rows.length?rows.map((r,i)=>`<div class="leaderboard-row"><strong>#${i+1} ${escapeHTML(r.nickname||r.email||r.user_id)}</strong><span>${r.score} XP</span></div>`).join(''):'<div class="muted">Пока нет данных.</div>';}catch(e){root.innerHTML=`<div class="notice notice-danger">${escapeHTML(e.message)}</div>`;}}};

const EventController={bind(){document.addEventListener('click',this.onClick.bind(this)); document.addEventListener('submit',this.onSubmit.bind(this)); document.addEventListener('change',this.onChange.bind(this)); document.addEventListener('input',this.onInput.bind(this));},
  async onClick(event){const target=event.target.closest('[data-action]'); if(!target)return; const action=target.dataset.action; try{switch(action){
    case 'auth:set-mode': UI.setAuthMode(target.dataset.authMode); break; case 'auth:toggle-mode': UI.toggleAuthMode(); break; case 'auth:logout': await AuthService.logout(); break;
    case 'nav:set-category': UI.setCategory(target.dataset.category); break; case 'nav:open-view': UI.openView(target.dataset.view); break; case 'nav:back': UI.openView('moderation'); break; case 'ui:toggle-theme': UI.toast('Тёмная тема уже активна.','warning'); break;
    case 'modal:close': UI.closeModal(target.dataset.modal); if(target.dataset.modal==='confirmModal')ReportsTableModule.handleModalClose(); break;
    case 'trainer:start': TrainerModule.start(); break; case 'trainer:reset': TrainerModule.reset(); break; case 'trainer:verdict': await TrainerModule.verdict(target.dataset.verdict); QuestsModule.render(); break; case 'trainer:skip': TrainerModule.skip(); break;
    case 'timeattack:start': TimeAttackModule.start(); break; case 'timeattack:reset': TimeAttackModule.reset(); break; case 'timeattack:answer': await TimeAttackModule.answer(target.dataset.verdict); QuestsModule.render(); break; case 'complaints:answer': await ComplaintsModule.answer(target.dataset.id,target.dataset.choice); QuestsModule.render(); break; case 'quests:claim': await QuestsModule.claim(target.dataset.id); break;
    case 'reports:load': await ReportModule.loadForReview(); break; case 'reports:approve': await ReportModule.process(target.dataset.id,target.dataset.status||'Норма',target.dataset.xp||15); break; case 'reports:reject': await ReportModule.process(target.dataset.id,'Не засчитано',0); break;
    case 'reports-table:refresh': await ReportsTableModule.load(); break; case 'reports-table:prev-week': await ReportsTableModule.prevWeek(); break; case 'reports-table:next-week': await ReportsTableModule.nextWeek(); break; case 'reports-table:show-proofs': await ReportsTableModule.showProofs(target.dataset.reportId); break;
    case 'shop:buy': await ShopModule.buy({itemId:target.dataset.itemId,price:target.dataset.price,title:target.dataset.title}); break; case 'shop:add-item': await ShopModule.addItemFromLeadership(); break; case 'shop:edit-item': UI.toast('Редактирование товара будет отдельным мини-этапом.','warning'); break; case 'shop:delete-item': await ShopModule.deleteSelectedItemFromLeadership(); break;
    case 'game:open': GameModule.open(target.dataset.game); break; case 'game:start-generic': await GameModule.startGeneric(); break; case 'game:start-fortune': await GameModule.startFortune(); break; case 'game:coin': await GameModule.playCoin(target.dataset.choice); break; case 'game:choose-safe': await GameModule.chooseSafe(target.dataset.safe); break; case 'game:john-wick-answer': await GameModule.answerQuiz(target.dataset.index); break;
    case 'leadership:add-moderator': await LeadershipModule.addModerator(); break; case 'leadership:remove-user-role': await LeadershipModule.removeUserRole(target.dataset.userId); break; case 'leadership:update-xp': await LeadershipModule.updateXp(); break; case 'leadership:delete-user': await LeadershipModule.deleteSelectedUser(); break; case 'leadership:send-hidden-check': await LeadershipModule.sendHiddenCheck(); break;
    case 'creator:update-xp': await CreatorModule.updateXp(); break; case 'creator:add-admin': await CreatorModule.addAdmin(); break; case 'creator:remove-admin': await CreatorModule.removeAdmin(); break; case 'creator:remove-admin-row': await CreatorModule.removeAdminRow(target.dataset.userId,target.dataset.role); break; case 'creator:save-gemini-key': await SettingsService.saveGeminiConfig(); break; case 'creator:save-deepseek-key': await SettingsService.saveDeepSeekConfig(); break; case 'creator:clear-deepseek-key': await SettingsService.clearDeepSeekConfig(); break; case 'creator:toggle-gemini-key': SettingsService.togglePasswordInput('creatorGeminiApiKeyInput'); break; case 'creator:toggle-deepseek-key': SettingsService.togglePasswordInput('creatorDeepSeekApiKeyInput'); break; case 'creator:paste-gemini-key': await SettingsService.pasteToInput('creatorGeminiApiKeyInput'); break; case 'creator:paste-deepseek-key': await SettingsService.pasteToInput('creatorDeepSeekApiKeyInput'); break;
    case 'logs:load': await AdminLogModule.load(); break; case 'ai:clear-chat': AIModule.clearChat(); break; case 'ai:analyze-report': await AIModule.analyzeReport(target.dataset.id); break; case 'ai:use-example': AIModule.useExample(target.dataset.text||''); break; case 'instruction:scroll': AIModule.scrollToBlock(target.dataset.target); break;
    default: UI.toast(`Неизвестное действие: ${action}`,'warning');
  }}catch(e){UI.toast(e.message||String(e),'error');}},
  async onSubmit(event){const form=event.target; try{if(form.id==='authForm'){event.preventDefault(); await AuthService.submitAuthForm(form,event.submitter); return;} if(form.id==='reportForm'){event.preventDefault(); await ReportModule.submit(form,event.submitter); return;} if(form.id==='inactiveForm'){event.preventDefault(); await InactiveModule.submit(form,event.submitter); return;} if(form.id==='aiChatForm'){event.preventDefault(); await AIModule.submitChat(form,event.submitter);}}catch(e){UI.toast(e.message||String(e),'error'); if(form.id==='reportForm')UI.setMessage('reportResultText',e.message,'error'); if(form.id==='inactiveForm')UI.setMessage('inactiveResultText',e.message,'error');}},
  onChange(event){const target=event.target; if(target.id==='reportFileInput')ReportModule.handleFiles(target); if(target.matches('[data-action="reports-table:update-status"]'))ReportsTableModule.updateStatus(target).catch(e=>UI.toast(e.message||String(e),'error'));},
  onInput(event){const target=event.target; if(target.id==='guideSearchInput')AIModule.searchInstruction(target.value);}
};

const App={async init(){if(AppState.isBooted)return; AppState.isBooted=true; try{UI.initStaticState(); EventController.bind(); SupabaseService.init(); await AuthService.init(); await sleepFrame(); if(AppState.user){await XpService.refreshUiBalances(); await LeaderboardModule.load(); await ShopModule.load(); await QuestsModule.loadCompleted(); await TrainerModule.init(); await LeadershipModule.init(); await CreatorModule.init();} console.info(`${CONFIG.appName} ${CONFIG.version} запущен.`);}catch(e){console.error(e); UI.showAuth(); UI.setMessage('authMessage',e.message||String(e),'error'); UI.toast('Ошибка запуска приложения.','error');}}};

document.addEventListener('DOMContentLoaded',()=>App.init());
